def process_graph(graph_data):

    graph_copy = copy.deepcopy(graph_data)

    # Find the control domain node
    control_domain_node = None
    for node in graph_copy.nodes(data=True):
        if node[1].get('name') == 'ju1.a4.dom' and 'EK_CONTROL_DOMAIN' in node[1].get('type', []):
            control_domain_node = node[0]
            break

    if not control_domain_node:
        return_object = {
            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }
        return return_object

    # Get all child nodes of the control domain
    child_nodes = []
    for edge in graph_copy.edges(data=True):
        if edge[0] == control_domain_node and 'RK_CONTAINS' in edge[2].get('type', []):
            child_node_id = edge[1]
            child_node_data = graph_copy.nodes[child_node_id]
            child_nodes.append((child_node_id, child_node_data))

    # For each child node, calculate total physical capacity by summing all PORT capacities underneath
    result_list = []
    for child_node_id, child_node_data in child_nodes:
        total_capacity = 0

        # DFS to find all PORT nodes under this child
        stack = [child_node_id]
        visited = set()

        while stack:
            current_node = stack.pop()
            if current_node in visited:
                continue
            visited.add(current_node)

            # Check if current node is a PORT
            node_attrs = graph_copy.nodes[current_node]
            if 'EK_PORT' in node_attrs.get('type', []):
                total_capacity += node_attrs.get('physical_capacity_bps', 0)

            # Add successors to stack
            for successor in graph_copy.successors(current_node):
                edge_data = graph_copy.get_edge_data(current_node, successor)
                if edge_data and 'RK_CONTAINS' in edge_data.get('type', []):
                    stack.append(successor)

        result_list.append((child_node_data.get('name'), total_capacity))

    # Sort by total physical capacity in descending order
    result_list.sort(key=lambda x: x[1], reverse=True)

    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    return_object = {
        'type': 'list',
        'data': result_list,
        'updated_graph': graph_json
    }
    return return_object

